import { readFileSync, existsSync, readdirSync } from "node:fs";
import assert from "node:assert/strict";

const result = JSON.parse(readFileSync("RESULT.json", "utf8"));
assert.equal(result.alpha, "alpha-complex-77");
assert.equal(result.beta, "beta-complex-88");
assert.equal(result.gamma, "gamma-complex-99");
assert.equal(result.delta, "delta-complex-55");
assert.equal(result.token, "MEGA-COMPLEX-TOKEN-2026");
assert.equal(result.logTailMarker, "MARKER-0799");
assert.equal(result.noiseCount, 24);

const done = readFileSync("DONE.md", "utf8");
assert.match(done, /MEGA-COMPLEX-TOKEN-2026/);
assert.match(done, /alpha-complex-77/);
assert.match(done, /beta-complex-88/);
assert.match(done, /gamma-complex-99/);
assert.match(done, /delta-complex-55/);
assert.match(done, /MARKER-0799/);
assert.match(done, /DELTA-KEEP-ALIVE/);

const scratch = existsSync(".reaper/memory/scratch.md")
  ? readFileSync(".reaper/memory/scratch.md", "utf8")
  : "";
assert.match(scratch, /MEGA-COMPLEX-TOKEN-2026/);
assert.match(scratch, /alpha-complex-77/);
assert.match(scratch, /beta-complex-88/);

const noise = readdirSync("noise").filter((f) => /^n\d{2}\.txt$/.test(f));
assert.ok(noise.length >= 24, `expected >=24 noise files, got ${noise.length}`);

const manifest = JSON.parse(readFileSync("noise/MANIFEST.json", "utf8"));
assert.equal(manifest.count, 24);
assert.ok(Array.isArray(manifest.files) && manifest.files.length === 24);

const report = readFileSync("reports/CONTEXT_SURVIVAL.md", "utf8");
assert.match(report, /MEGA-COMPLEX-TOKEN-2026/);
assert.match(report, /bash_head_tail|full_summary|scratchpad/i);

console.log("ok");
